  -- ══════════════════════════════════════════════════════════════════════════
  -- MELHORIA 1: Comercial — Prospecção e Qualificação de Leads
  -- ══════════════════════════════════════════════════════════════════════════
  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Prospecção e Qualificação de Leads',
    'tbo-com-001-prospeccao-e-qualificacao-de-leads',
    'comercial',
    'processo',
    'Processo completo de geração e qualificação de leads para garantir que a TBO invista tempo comercial apenas em oportunidades com real fit de perfil, orçamento e timing de lançamento imobiliário.',
    E'## Prospecção e Qualificação de Leads\n\n### 1. Objetivo\nPadronizar o processo de geração e qualificação de leads para garantir que a TBO invista tempo comercial apenas em oportunidades com real fit de perfil, orçamento e timing de lançamento. Meta: taxa de conversão de lead qualificado → proposta > 60%, eliminando reuniões com leads fora do perfil ideal (ICP).\n\n### 2. Escopo\n**Quem executa:** Ruy Lima (Dir. Comercial) + equipe comercial\n**Quando se aplica:** Todo lead inbound ou outbound, antes de qualquer reunião de diagnóstico\n**Limites:** Este SOP cobre até a qualificação e agendamento de diagnóstico. Elaboração de proposta → SOP tbo-com-002. Fechamento → SOP tbo-com-003.\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Identificar e registrar lead no CRM | Ruy Lima | — | — | Marco Andolfato |\n| Aplicar filtro BANT-R (pré-qualificação) | Ruy Lima | — | — | — |\n| Conduzir reunião de diagnóstico | Ruy Lima | Marco (fit criativo) | Líder BU (capacidade) | Ops |\n| Aprovar ou desqualificar lead | Ruy + Marco | — | — | Financeiro (se deal > R$100k) |\n| Atualizar CRM com status e próximos passos | Ruy Lima | — | — | Marco Andolfato |\n\n### 4. Pré-requisitos\n\n- [ ] Acesso ao CRM (módulo Comercial do TBO OS)\n- [ ] ICP (Ideal Customer Profile) da TBO atualizado (ver documento de estratégia comercial)\n- [ ] Template de e-mail de prospecção aprovado\n- [ ] Calendário disponível para agendamento de diagnóstico (mínimo 2 slots/semana)\n- [ ] Acesso ao LinkedIn Sales Navigator (para outbound)\n\n### 5. Procedimento\n\n**5.1 Classificação de Fonte do Lead**\n\n1. Identificar a fonte do lead:\n   - **Inbound orgânico**: LinkedIn, referência de cliente, evento, podcast\n   - **Inbound pago**: formulário de campanha, landing page\n   - **Outbound**: prospecção ativa por Ruy (LinkedIn, cold email, networking)\n   - **Parceria/indicação**: imobiliária, arquiteto, consultor\n2. Registrar no CRM com: nome, empresa, cargo, fonte, data de entrada\n3. Classificar como `lead-novo` no pipeline\n\n**5.2 Pré-Qualificação BANT-R (< 5 minutos)**\n\nResponder às 5 perguntas sem contato com o lead (pesquisa no LinkedIn, site, Google):\n\n| Critério | Pergunta | Mínimo para avançar |\n|---|---|---|\n| **B**udget | A empresa tem budget para agência premium? | Evidência de lançamentos anteriores, porte da incorporadora |\n| **A**uthority | Quem contata é decisor? (CEO, Dir. Marketing, sócio) | Cargo com poder de decisão ou próximo ao decisor |\n| **N**eed | Há um lançamento planejado nos próximos 6-12 meses? | Indicador de projeto em andamento |\n| **T**imeline | O timing está alinhado? | Lançamento em janela de 3-12 meses |\n| **R**eputação | A empresa tem reputação compatível com a TBO? | Sem histórico de calote, processos ou más práticas |\n\n> **Regra:** Se 3 ou mais critérios não forem atendidos → desqualificar imediatamente. Não agendar reunião.\n\n**5.3 Contato Inicial (se pré-qualificado)**\n\n1. Enviar mensagem de conexão no LinkedIn (texto personalizado, < 300 caracteres)\n2. Se aceito: enviar mensagem de qualificação:\n   - Breve apresentação da TBO\n   - Referência ao projeto/empreendimento específico deles\n   - Pergunta sobre timeline e interesse\n3. Se inbound (lead veio até nós): responder em < 2 horas úteis\n4. Propor call de diagnóstico de 30 minutos\n\n**5.4 Reunião de Diagnóstico (30-45 min)**\n\nEstrutura obrigatória:\n\n1. **Abertura (5 min)**: Apresentar TBO com 3 cases relevantes para o segmento do lead\n2. **Escuta ativa (15 min)**: Perguntar sobre:\n   - Empreendimento (tipologia, localização, VSO esperado, valor de lançamento)\n   - Histórico de comunicação (o que já fizeram, o que funcionou, o que não funcionou)\n   - Equipe e decisores (quem aprova, quem executa internamente)\n   - Concorrentes que estão avaliando\n   - Budget e expectativa de ROI\n3. **Posicionamento (10 min)**: Apresentar abordagem TBO para o contexto específico deles\n4. **Próximos passos (5 min)**: Alinhar se há fit e propor próximo passo (proposta vs. declinar)\n5. **Não-negociáveis**: Se budget < R$40k/mês ou projeto fora do segmento imobiliário → declinar educadamente\n\n**5.5 Decisão Pós-Diagnóstico**\n\n- **Lead qualificado** → Mover para `em-proposta` no CRM. Iniciar SOP tbo-com-002.\n- **Lead a desenvolver** (fit mas timing errado) → Mover para `nurturing`. Agendar follow-up em 60 dias.\n- **Lead desqualificado** → Mover para `perdido`. Registrar motivo. Pode indicar para parceiro se boa relação.\n\n**5.6 Registro no CRM**\n\nApós toda reunião, registrar no CRM em < 24h:\n- Resumo da conversa (3-5 bullets)\n- Qualificação BANT-R (score por critério)\n- Decisão (qualificado/nurturing/perdido) e motivo\n- Próxima ação com data e responsável\n\n### 6. Checklist de Validação\n\n**Pré-qualificação:**\n- [ ] Lead pesquisado no LinkedIn + site da empresa\n- [ ] BANT-R respondido (5 critérios)\n- [ ] Decisão de avançar ou desqualificar registrada no CRM\n\n**Pós-diagnóstico:**\n- [ ] Notas de reunião no CRM (< 24h após call)\n- [ ] Status do lead atualizado no pipeline\n- [ ] Próxima ação definida com data\n- [ ] Marco informado sobre deals > R$100k/mês\n\n**Qualidade do processo:**\n- [ ] Lead só avançou com ≥ 3 critérios BANT-R positivos\n- [ ] Reunião de diagnóstico seguiu estrutura (abertura → escuta → posicionamento → próximos passos)\n- [ ] Nenhum lead desqualificado recebeu proposta\n\n### 7. Ferramentas e Recursos\n\n- **CRM TBO OS**: módulo Comercial (crm_deals, crm_stages)\n- **LinkedIn Sales Navigator**: prospecção outbound\n- **Calendly**: agendamento de diagnóstico (link público)\n- **Notion**: playbook comercial TBO (cases, pricing, ICP)\n- **Gmail + templates**: e-mails de prospecção padronizados\n\n### 8. SLAs e Métricas\n\n| Métrica | Meta |\n|---|---|\n| Resposta a lead inbound | < 2 horas úteis |\n| Taxa de conversão lead → qualificado | > 30% dos leads pré-qualificados |\n| Taxa de conversão qualificado → proposta | > 60% |\n| Taxa de conversão proposta → fechamento | > 40% (SOP COM-003) |\n| Tempo médio de qualificação | < 5 dias da entrada até decisão |\n| Registros no CRM atualizados | 100% (zero reunião sem nota no CRM) |\n\n**Funil esperado:**\n- 100 leads → 40 pré-qualificados → 25 diagnósticos → 15 propostas → 6 fechamentos/mês\n\n### 9. Troubleshooting\n\n**Lead qualificado some após diagnóstico (ghosting):**\n→ Fazer 2 tentativas de follow-up (D+3, D+7)\n→ Se sem resposta: mover para `nurturing`, agendar recontato em 45 dias\n→ Nunca enviar proposta para lead que sumiu sem compromisso\n\n**Lead pressiona por proposta rápida sem diagnóstico:**\n→ Regra: nunca proposta sem diagnóstico. Máximo de 30 minutos de call\n→ Se recusar call: forte sinal de desqualificação. Avaliar enviar conteúdo informativo\n\n**Lead fora do ICP mas insistente:**\n→ Ruy tem autonomia para declinar. Usar resposta-padrão de declínio (ver template)\n→ Não negocie escopo ou preço para encaixar lead fora do perfil\n\n**Budget insuficiente mas projeto interessante:**\n→ Avaliar com Marco se há interesse estratégico (reputação, case de portfólio)\n→ Exceções devem ser aprovadas por Marco + Ruy juntos. Máximo 1 por trimestre\n\n### 10. Template Anexo\n\n**Template: E-mail de Prospecção Outbound**\n```\nAssunto: [Nome do Empreendimento] — visão criativa TBO\n\nOlá, [Nome],\n\nAcompanho o [Nome do Empreendimento] e a trajetória da [Empresa] — projeto com potencial visual forte.\n\nA TBO atua em direção criativa, branding e comunicação para lançamentos imobiliários. Nos últimos 12 meses, entregamos campanhas para [case 1] e [case 2], com [resultado específico].\n\nGostaria de conversar 30 minutos sobre o posicionamento criativo do [Empreendimento]?\n\nRuy Lima\nDiretor Comercial | TBO\n[LinkedIn] | [site]\n```\n\n**Template: Notas de CRM Pós-Diagnóstico**\n```\n# Diagnóstico — [Nome do Lead] | [Data]\n\n## Contexto do Empreendimento\n- Tipologia: \n- Localização: \n- VGV estimado: \n- Lançamento previsto: \n\n## BANT-R\n- Budget: [ ] ✓ [ ] ✗ — Notas:\n- Authority: [ ] ✓ [ ] ✗ — Notas:\n- Need: [ ] ✓ [ ] ✗ — Notas:\n- Timeline: [ ] ✓ [ ] ✗ — Notas:\n- Reputação: [ ] ✓ [ ] ✗ — Notas:\n\n## Decisão\n- [ ] Qualificado → Proposta (SOP COM-002)\n- [ ] Nurturing — Recontato em: ___\n- [ ] Desqualificado — Motivo: ___\n\n## Próxima Ação\n- O quê: \n- Quem: \n- Quando: \n```',
    '',
    'published',
    'critical',
    ARRAY['prospecção', 'leads', 'qualificação', 'BANT', 'CRM', 'comercial', 'pipeline', 'diagnóstico', 'ICP'],
    1,
    2
  ) ON CONFLICT (tenant_id, slug) DO UPDATE SET
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    content = EXCLUDED.content,
    content_html = EXCLUDED.content_html,
    priority = EXCLUDED.priority,
    tags = EXCLUDED.tags,
    version = EXCLUDED.version,
    updated_at = NOW();

  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-com-001-prospeccao-e-qualificacao-de-leads';

  DELETE FROM knowledge_sop_steps WHERE sop_id = v_sop_id;

  INSERT INTO knowledge_sop_steps (sop_id, title, content, content_html, order_index, step_type) VALUES
  (v_sop_id, 'Objetivo', E'Padronizar o processo de geração e qualificação de leads para garantir que a TBO invista tempo comercial apenas em oportunidades com real fit de perfil, orçamento e timing de lançamento. Meta: taxa de conversão de lead qualificado → proposta > 60%, eliminando reuniões com leads fora do ICP.', '', 0, 'step'),
  (v_sop_id, 'Escopo', E'**Quem executa:** Ruy Lima (Dir. Comercial) + equipe comercial\n**Quando se aplica:** Todo lead inbound ou outbound, antes de qualquer reunião de diagnóstico\n**Limites:** Cobre até qualificação e agendamento de diagnóstico. Proposta → SOP tbo-com-002. Fechamento → SOP tbo-com-003.', '', 1, 'step'),
  (v_sop_id, 'RACI — Responsabilidades', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Identificar e registrar lead no CRM | Ruy Lima | — | — | Marco Andolfato |\n| Aplicar filtro BANT-R (pré-qualificação) | Ruy Lima | — | — | — |\n| Conduzir reunião de diagnóstico | Ruy Lima | Marco (fit criativo) | Líder BU (capacidade) | Ops |\n| Aprovar ou desqualificar lead | Ruy + Marco | — | — | Financeiro (deals > R$100k) |\n| Atualizar CRM com status e próximos passos | Ruy Lima | — | — | Marco Andolfato |', '', 2, 'step'),
  (v_sop_id, 'Pré-requisitos', E'- Acesso ao CRM (módulo Comercial do TBO OS)\n- ICP (Ideal Customer Profile) da TBO atualizado\n- Templates de e-mail de prospecção aprovados\n- Calendário com slots disponíveis (mínimo 2/semana)\n- Acesso ao LinkedIn Sales Navigator (para outbound)', '', 3, 'step'),
  (v_sop_id, 'Procedimento', E'**5.1 Classificação de Fonte:** Registrar lead no CRM com fonte, nome, empresa, cargo e data.\n\n**5.2 Pré-Qualificação BANT-R:** Responder 5 critérios (Budget, Authority, Need, Timeline, Reputação) com pesquisa prévia. ≥ 3 critérios negativos = desqualificar imediatamente.\n\n**5.3 Contato Inicial:** LinkedIn ou e-mail personalizado. Propor diagnóstico de 30 min.\n\n**5.4 Reunião de Diagnóstico (30-45 min):** Abertura com cases → Escuta ativa (empreendimento, histórico, budget) → Posicionamento TBO → Próximos passos.\n\n**5.5 Decisão Pós-Diagnóstico:** Qualificado → proposta | A desenvolver → nurturing (60 dias) | Desqualificado → perdido + motivo.\n\n**5.6 Registro no CRM (< 24h):** Resumo da conversa, score BANT-R, decisão e próxima ação com data.', '', 4, 'step'),
  (v_sop_id, 'Checklist de Validação', E'**Pré-qualificação:**\n- [ ] Lead pesquisado (LinkedIn + site)\n- [ ] BANT-R respondido (5 critérios)\n- [ ] Decisão registrada no CRM\n\n**Pós-diagnóstico:**\n- [ ] Notas no CRM < 24h após call\n- [ ] Status do lead atualizado no pipeline\n- [ ] Próxima ação definida com data\n- [ ] Marco informado sobre deals > R$100k/mês\n\n**Qualidade:**\n- [ ] Lead só avançou com ≥ 3 critérios BANT-R positivos\n- [ ] Estrutura de diagnóstico seguida\n- [ ] Nenhum lead desqualificado recebeu proposta', '', 5, 'checkpoint'),
  (v_sop_id, 'Ferramentas e Recursos', E'- **CRM TBO OS**: módulo Comercial (crm_deals, crm_stages)\n- **LinkedIn Sales Navigator**: prospecção outbound\n- **Calendly**: agendamento de diagnóstico\n- **Notion**: playbook comercial TBO (cases, pricing, ICP)\n- **Gmail + templates**: e-mails de prospecção padronizados', '', 6, 'tip'),
  (v_sop_id, 'SLAs e Métricas', E'| Métrica | Meta |\n|---|---|\n| Resposta a lead inbound | < 2 horas úteis |\n| Taxa lead → qualificado | > 30% |\n| Taxa qualificado → proposta | > 60% |\n| Taxa proposta → fechamento | > 40% |\n| Tempo de qualificação | < 5 dias da entrada |\n| CRM atualizado | 100% (zero reunião sem nota) |\n\n**Funil esperado:** 100 leads → 40 pré-qualificados → 25 diagnósticos → 15 propostas → 6 fechamentos/mês', '', 7, 'note'),
  (v_sop_id, 'Troubleshooting', E'**Ghosting após diagnóstico:** 2 tentativas de follow-up (D+3, D+7). Se sem resposta → nurturing. Nunca proposta sem compromisso.\n\n**Pressão por proposta rápida sem diagnóstico:** Regra inegociável. Máximo 30 min de call primeiro. Se recusar → sinal de desqualificação.\n\n**Lead fora do ICP insistente:** Ruy tem autonomia para declinar. Usar resposta-padrão. Não negocie escopo ou preço para encaixar lead errado.\n\n**Budget insuficiente mas projeto interessante:** Avaliar com Marco se há interesse estratégico. Exceções aprovadas por Marco + Ruy. Máximo 1/trimestre.', '', 8, 'warning'),
  (v_sop_id, 'Templates Prontos para Uso', E'**E-mail de Prospecção Outbound:**\n```\nAssunto: [Empreendimento] — visão criativa TBO\n\nOlá, [Nome],\n\nAcompanho o [Empreendimento] e a trajetória da [Empresa].\nA TBO atua em direção criativa e branding para lançamentos imobiliários. Entregamos [case] com [resultado].\n\nGostaria de conversar 30 min sobre o posicionamento criativo?\n\nRuy Lima | TBO\n```\n\n**Notas de CRM Pós-Diagnóstico:**\nVer template completo no conteúdo principal do SOP.', '', 9, 'tip');

  -- ══════════════════════════════════════════════════════════════════════════
  -- MELHORIA 2: RH — Recrutamento e Seleção
  -- ══════════════════════════════════════════════════════════════════════════
  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Recrutamento e Seleção',
    'tbo-rh-001-recrutamento-e-selecao',
    'recursos-humanos',
    'processo',
    'Processo completo de recrutamento e seleção da TBO — da abertura de vaga à proposta de contratação, garantindo agilidade, qualidade técnica e fit cultural com a equipe.',
    E'## Recrutamento e Seleção\n\n### 1. Objetivo\nPadronizar o processo de recrutamento e seleção da TBO para garantir agilidade (< 30 dias da abertura à oferta), qualidade técnica (nível sênior ou acima para posições estratégicas) e fit cultural com os valores da agência. Eliminar contratações por urgência que resultem em desligamento nos primeiros 6 meses.\n\n### 2. Escopo\n**Quem executa:** Marco Andolfato (decisão final) + Ruy Lima (entrevista comportamental) + Líder de BU (entrevista técnica) + Ops (logística)\n**Quando se aplica:** Toda abertura de vaga — CLT, PJ, freelancer recorrente (>40h/mês) ou estágio\n**Limites:** Não cobre onboarding (SOP tbo-rh-002) nem PDI (SOP tbo-rh-005). Freelancers pontuais seguem SOP tbo-geral-006.\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Definir necessidade e perfil da vaga | Líder de BU | Marco Andolfato | Ruy (impacto financeiro) | Ops |\n| Redigir job description | Ops (com Líder BU) | Marco Andolfato | — | — |\n| Divulgar vaga | Ops | Marco | — | Equipe TBO |\n| Triagem de currículos | Ops | Líder de BU | — | — |\n| Entrevista técnica (1ª etapa) | Líder de BU | — | — | Ops |\n| Entrevista comportamental (2ª etapa) | Ruy Lima | — | Marco (se senior) | — |\n| Entrevista final / decisão | Marco Andolfato | — | Ruy, Líder BU | — |\n| Fazer oferta e negociar | Ruy Lima | Marco Andolfato | — | Financeiro |\n| Iniciar onboarding | Ops | — | Líder BU | Marco, Ruy |\n\n### 4. Pré-requisitos\n\n- [ ] Budget aprovado para a posição (Marco + Ruy)\n- [ ] Job description redigido e validado pelo Líder de BU\n- [ ] Canais de divulgação definidos (LinkedIn, Gupy, indicações, comunidades)\n- [ ] Agenda de entrevistas disponível (Líder BU + Ruy + Marco)\n- [ ] Formulário de avaliação de candidato preenchido para triagem\n\n### 5. Procedimento\n\n**5.1 Abertura de Vaga (D-0)**\n\n1. Líder de BU preenche formulário de solicitação de vaga:\n   - Descrição da necessidade (aumento de capacidade, substituição, nova função)\n   - Hard skills obrigatórias (lista não negociável)\n   - Hard skills desejáveis (bônus, não eliminatórios)\n   - Soft skills prioritárias (2-3 no máximo, não genéricas)\n   - Regime de contratação (CLT/PJ) e faixa de remuneração\n   - Data necessária de início\n2. Marco aprova a abertura com budget validado\n3. Ops redige job description completo:\n   - Título da posição (claro, sem jargões internos)\n   - Descrição do projeto/contexto da TBO\n   - Responsabilidades principais (5-7 bullets)\n   - Requisitos obrigatórios\n   - Diferenciais desejáveis\n   - O que oferecemos (cultura, benefícios, ambiente)\n4. Divulgar nas plataformas selecionadas\n5. Comunicar à equipe TBO para indicações internas\n\n**5.2 Triagem (D+3 a D+10)**\n\n1. Ops coleta candidaturas e organiza em planilha de tracking\n2. Aplicar filtro binário (avança/não avança):\n   - Portfolio ou trabalho anterior compatível com a TBO?\n   - Hard skills obrigatórias presentes?\n   - Faixa de remuneração compatível?\n3. Candidatos aprovados: marcar entrevista técnica com Líder de BU\n4. Candidatos reprovados: enviar e-mail de agradecimento < 48h\n\n**5.3 Entrevista Técnica — 1ª Etapa (30-45 min)**\n\nConduzida pelo Líder de BU:\n1. Apresentação do candidato (trajetória, projetos favoritos)\n2. Análise técnica: apresentar 2-3 cases TBO similares ao trabalho do candidato → pedir análise/crítica\n3. Teste prático (opcional mas recomendado para posições sênior):\n   - D3D: enviar briefing de render para mini-exercício (prazo 48h)\n   - MKT: análise de campanha real + proposta de melhoria\n   - BRD: brief de naming ou análise de identidade visual\n4. Preencher formulário de avaliação técnica (score 1-5 por critério)\n5. Avançar apenas candidatos com score técnico ≥ 4/5\n\n**5.4 Entrevista Comportamental — 2ª Etapa (45-60 min)**\n\nConduzida por Ruy Lima:\n1. Apresentar cultura e valores da TBO (não genérico — concreto: como decidimos, como discordamos, ritmo de trabalho)\n2. Perguntas comportamentais (método STAR: Situação, Tarefa, Ação, Resultado):\n   - "Descreva um projeto que você refaria diferente. O que mudaria?"\n   - "Como você lida com cliente que rejeita seu trabalho sem dar feedback claro?"\n   - "Conte de um conflito com colega de trabalho. Como resolveu?"\n   - "O que mais te frustra em ambientes de agência?"\n3. Apresentar os desafios reais da posição (não só os benefícios)\n4. Espaço para perguntas do candidato (qualidade das perguntas é sinal importante)\n5. Preencher formulário comportamental (fit cultural 1-5)\n\n**5.5 Entrevista Final — Decisão (30 min, se necessário)**\n\n1. Marco conduz para posições sênior ou estratégicas\n2. Foco em: visão de carreira, valores, expectativa de crescimento na TBO\n3. Compartilhar transparentemente: desafios, limitações, cultura real\n4. Colher input de Ruy e Líder BU para decisão final\n5. Decisão em até 48h após última entrevista\n\n**5.6 Oferta e Fechamento**\n\n1. Ruy faz oferta por vídeo (nunca só por e-mail para posições sênior)\n2. Apresentar: remuneração, benefícios, início previsto, próximos passos\n3. Prazo para resposta: 3 dias úteis\n4. Se aceita: iniciar processo de onboarding (SOP tbo-rh-002)\n5. Se não aceita: registrar motivo no tracking, avaliar se há alternativa viável\n6. Comunicar decisão (contratação ou encerramento) a todos os candidatos entrevistados em < 5 dias úteis\n\n### 6. Checklist de Validação\n\n**Abertura de vaga:**\n- [ ] Budget aprovado por Marco + Ruy\n- [ ] Job description validado pelo Líder de BU\n- [ ] Vaga divulgada em ≥ 2 canais\n- [ ] Equipe TBO comunicada para indicações\n\n**Triagem:**\n- [ ] Todos os candidatos com resposta (sim ou não) em < 48h\n- [ ] Planilha de tracking atualizada com status de cada candidato\n\n**Entrevistas:**\n- [ ] Formulário de avaliação técnica preenchido (1ª etapa)\n- [ ] Formulário comportamental preenchido (2ª etapa)\n- [ ] Decisão documentada com justificativa\n\n**Oferta:**\n- [ ] Oferta apresentada por vídeo (não e-mail)\n- [ ] Todos os entrevistados com feedback < 5 dias úteis\n- [ ] Candidato contratado com início e onboarding agendados\n\n### 7. Ferramentas e Recursos\n\n- **TBO OS — RH**: tracking de candidatos, formulários de avaliação\n- **LinkedIn Jobs + Sales Navigator**: divulgação + prospecção ativa\n- **Gupy**: ATS para posições com volume maior de candidatos\n- **Google Forms**: formulário de triagem e avaliação\n- **Google Meet**: entrevistas (gravar com permissão do candidato)\n- **Notion**: banco de talentos (candidatos aprovados mas não contratados agora)\n\n### 8. SLAs e Métricas\n\n| Etapa | SLA |\n|---|---|\n| Resposta a candidatos reprovados na triagem | < 48h |\n| Tempo da abertura à oferta | < 30 dias |\n| Feedback a entrevistados após decisão | < 5 dias úteis |\n| Taxa de aprovação de candidatos na 1ª etapa | 20-30% dos triados |\n| Taxa de aceite de ofertas | > 80% |\n| Taxa de retenção em 6 meses | > 90% |\n\n**KPIs de qualidade:**\n- Zero contratações sem portfolio revisado pelo Líder de BU\n- Zero ofertas feitas sem score técnico ≥ 4/5\n- Zero desligamentos por desalinhamento cultural nos primeiros 3 meses\n\n### 9. Troubleshooting\n\n**Sem candidatos qualificados após 15 dias:**\n→ Revisar job description (pode estar muito restritivo)\n→ Ampliar canais: comunidades específicas (D3D: Render Engine, Blender Brasil; MKT: Caio Barbaresco, Growth Hackers)\n→ Ativar banco de talentos do Notion\n→ Avaliar indicações de colaboradores (pagar bônus de indicação)\n\n**Candidato recusa oferta:**\n→ Entender o motivo real (remuneração, localização, proposta concorrente)\n→ Se remuneração: avaliar margem de negociação com Marco e Ruy\n→ Se cultura/fit: não forçar — sinal de que a seleção funcionou corretamente\n→ Manter relacionamento: candidato certo agora pode ser certo no futuro\n\n**Urgência para preencher vaga (< 2 semanas):**\n→ Acionar banco de talentos primeiro\n→ Contato direto com freelancers recorrentes que já conhecem a operação\n→ Não pular etapa de entrevista técnica mesmo com urgência\n→ Contratação temporária (PJ/hora) enquanto processo formal ocorre\n\n**Desistência de candidato no meio do processo:**\n→ Registrar motivo no tracking (invaluável para calibrar o processo)\n→ Avançar com o próximo candidato qualificado na fila\n→ Se não houver fila: reabrir vaga imediatamente (não esperar)\n\n### 10. Template Anexo\n\n**Formulário de Avaliação de Candidato**\n```markdown\n# Avaliação de Candidato — TBO\n\n## Identificação\n- **Candidato:** \n- **Vaga:** \n- **Entrevistador:** \n- **Data:** \n\n## 1ª Etapa — Avaliação Técnica (Líder de BU)\n\n| Critério | Score (1-5) | Observações |\n|---|---|---|\n| Portfolio/trabalho anterior | | |\n| Hard skills obrigatórias | | |\n| Capacidade de execução | | |\n| Qualidade estética/técnica | | |\n| **Média técnica** | | |\n\n**Avança para 2ª etapa?** [ ] Sim [ ] Não\n**Justificativa:** \n\n## 2ª Etapa — Avaliação Comportamental (Ruy Lima)\n\n| Critério | Score (1-5) | Observações |\n|---|---|---|\n| Fit cultural (valores TBO) | | |\n| Comunicação e clareza | | |\n| Maturidade profissional | | |\n| Capacidade de receber feedback | | |\n| Autonomia e proatividade | | |\n| **Média comportamental** | | |\n\n**Avança para etapa final?** [ ] Sim [ ] Não\n**Justificativa:** \n\n## Decisão Final\n\n**Decisão:** [ ] Contratar [ ] Não contratar [ ] Banco de talentos\n**Remuneração proposta:** \n**Motivo da decisão:** \n**Próximos passos:** \n```',
    '',
    'published',
    'high',
    ARRAY['recrutamento', 'seleção', 'contratação', 'entrevista', 'RH', 'vaga', 'BANT', 'fit cultural', 'onboarding'],
    1,
    2
  ) ON CONFLICT (tenant_id, slug) DO UPDATE SET
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    content = EXCLUDED.content,
    content_html = EXCLUDED.content_html,
    priority = EXCLUDED.priority,
    tags = EXCLUDED.tags,
    version = EXCLUDED.version,
    updated_at = NOW();

  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-rh-001-recrutamento-e-selecao';

