  INSERT INTO knowledge_sop_steps (sop_id, title, content, content_html, order_index, step_type) VALUES
  (v_sop_id, 'Objetivo', E'Padronizar o processo de recrutamento e seleção da TBO para garantir agilidade (< 30 dias da abertura à oferta), qualidade técnica e fit cultural. Eliminar contratações por urgência que resultem em desligamento nos primeiros 6 meses.', '', 0, 'step'),
  (v_sop_id, 'Escopo', E'**Quem executa:** Marco (decisão final) + Ruy (comportamental) + Líder de BU (técnica) + Ops (logística)\n**Quando se aplica:** Toda abertura de vaga — CLT, PJ, freelancer recorrente (>40h/mês) ou estágio\n**Limites:** Não cobre onboarding (SOP tbo-rh-002) nem PDI (SOP tbo-rh-005).', '', 1, 'step'),
  (v_sop_id, 'RACI — Responsabilidades', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Definir necessidade e perfil da vaga | Líder de BU | Marco Andolfato | Ruy (impacto financeiro) | Ops |\n| Redigir job description | Ops (com Líder BU) | Marco Andolfato | — | — |\n| Divulgar vaga | Ops | Marco | — | Equipe TBO |\n| Triagem de currículos | Ops | Líder de BU | — | — |\n| Entrevista técnica (1ª etapa) | Líder de BU | — | — | Ops |\n| Entrevista comportamental (2ª etapa) | Ruy Lima | — | Marco (se sênior) | — |\n| Entrevista final / decisão | Marco Andolfato | — | Ruy, Líder BU | — |\n| Fazer oferta e negociar | Ruy Lima | Marco Andolfato | — | Financeiro |\n| Iniciar onboarding | Ops | — | Líder BU | Marco, Ruy |', '', 2, 'step'),
  (v_sop_id, 'Pré-requisitos', E'- Budget aprovado para a posição (Marco + Ruy)\n- Job description redigido e validado pelo Líder de BU\n- Canais de divulgação definidos (LinkedIn, Gupy, indicações, comunidades)\n- Agenda de entrevistas disponível\n- Formulário de avaliação preparado para triagem', '', 3, 'step'),
  (v_sop_id, 'Procedimento', E'**5.1 Abertura de Vaga (D-0):** Líder de BU preenche formulário de solicitação → Marco aprova budget → Ops redige job description → Divulgação em ≥ 2 canais → Comunicar equipe para indicações.\n\n**5.2 Triagem (D+3 a D+10):** Ops organiza candidaturas em planilha. Filtro binário: portfolio compatível? Hard skills presentes? Faixa de remuneração ok? Aprovados → entrevista técnica. Reprovados → e-mail de agradecimento em < 48h.\n\n**5.3 Entrevista Técnica 1ª Etapa (30-45 min):** Líder de BU analisa trajetória + cases + teste prático. Score técnico ≥ 4/5 para avançar.\n\n**5.4 Entrevista Comportamental 2ª Etapa (45-60 min):** Ruy conduz com método STAR. Apresentar cultura real (não só benefícios). Score de fit ≥ 4/5 para avançar.\n\n**5.5 Entrevista Final (se necessário):** Marco para posições sênior. Foco em visão de carreira e valores. Decisão em < 48h.\n\n**5.6 Oferta:** Ruy apresenta por vídeo. Prazo de resposta: 3 dias úteis. Todos os entrevistados com feedback < 5 dias úteis da decisão.', '', 4, 'step'),
  (v_sop_id, 'Checklist de Validação', E'**Abertura:**\n- [ ] Budget aprovado por Marco + Ruy\n- [ ] Job description validado pelo Líder de BU\n- [ ] Vaga em ≥ 2 canais\n- [ ] Equipe comunicada para indicações\n\n**Triagem:**\n- [ ] Todos candidatos com resposta em < 48h\n- [ ] Planilha de tracking atualizada\n\n**Entrevistas:**\n- [ ] Formulário técnico preenchido (1ª etapa)\n- [ ] Formulário comportamental preenchido (2ª etapa)\n- [ ] Decisão documentada com justificativa\n\n**Oferta:**\n- [ ] Apresentada por vídeo\n- [ ] Todos entrevistados com feedback < 5 dias úteis\n- [ ] Onboarding agendado (SOP tbo-rh-002)', '', 5, 'checkpoint'),
  (v_sop_id, 'Ferramentas e Recursos', E'- **TBO OS — RH**: tracking de candidatos e formulários de avaliação\n- **LinkedIn Jobs + Sales Navigator**: divulgação e prospecção ativa\n- **Gupy**: ATS para posições com volume maior\n- **Google Forms**: triagem e avaliação\n- **Google Meet**: entrevistas (gravar com permissão)\n- **Notion**: banco de talentos (aprovados mas não contratados agora)', '', 6, 'tip'),
  (v_sop_id, 'SLAs e Métricas', E'| Etapa | SLA |\n|---|---|\n| Resposta a reprovados na triagem | < 48h |\n| Tempo da abertura à oferta | < 30 dias |\n| Feedback a entrevistados após decisão | < 5 dias úteis |\n| Taxa de aceite de ofertas | > 80% |\n| Taxa de retenção em 6 meses | > 90% |\n\n**Zero:** contratações sem portfolio revisado | ofertas sem score técnico ≥ 4/5 | desligamentos por desalinhamento cultural nos primeiros 3 meses.', '', 7, 'note'),
  (v_sop_id, 'Troubleshooting', E'**Sem candidatos qualificados após 15 dias:** Revisar job description → ampliar canais → ativar banco de talentos → indicações com bônus.\n\n**Candidato recusa oferta:** Entender motivo real. Se remuneração → avaliar margem. Se cultura → não forçar. Manter relacionamento.\n\n**Urgência (< 2 semanas):** Banco de talentos primeiro → freelancers recorrentes → contratação temporária PJ/hora. Nunca pular entrevista técnica.\n\n**Desistência no meio do processo:** Registrar motivo → avançar próximo candidato → se não houver fila, reabrir vaga imediatamente.', '', 8, 'warning'),
  (v_sop_id, 'Template — Formulário de Avaliação de Candidato', E'Ver template completo no conteúdo principal do SOP. Inclui:\n- Seção de avaliação técnica (score 1-5 por critério)\n- Seção comportamental (método STAR)\n- Campo de decisão final com justificativa\n- Próximos passos definidos\n\nUso: preencher durante a entrevista, não depois. Subjetividade diminui com o tempo.', '', 9, 'tip');

  -- ══════════════════════════════════════════════════════════════════════════
  -- MELHORIA 3: Financeiro — Contas a Receber e Faturamento
  -- ══════════════════════════════════════════════════════════════════════════
  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Contas a Receber e Faturamento',
    'tbo-fin-001-contas-a-receber-e-faturamento',
    'financeiro',
    'processo',
    'Processo completo de emissão de NF, cobrança e conciliação de recebimentos da TBO — garantindo que 100% das entregas sejam faturadas, recebidas no prazo e registradas no DRE do ciclo correto.',
    E'## Contas a Receber e Faturamento\n\n### 1. Objetivo\nGarantir que 100% das entregas realizadas pela TBO sejam faturadas corretamente, cobradas no prazo e recebidas de acordo com o contrato. Zero receita não faturada. Zero NF emitida com dados errados. Fluxo de caixa previsível com visibilidade de 45 dias à frente.\n\n### 2. Escopo\n**Quem executa:** Financeiro TBO (responsável principal) + Atendimento (confirmação de entrega) + Ruy Lima (aprovação de crédito em casos especiais)\n**Quando se aplica:** Todo faturamento mensal — projetos em andamento, contratos de retainer, marcos de projeto, adiantamentos\n**Limites:** Não cobre Contas a Pagar (SOP tbo-fin-002) nem DRE/fluxo de caixa (SOP tbo-fin-003). Inadimplência avançada → SOP tbo-fin-005.\n\n**Ciclo financeiro TBO:** Dia 15 ao dia 15 do mês seguinte. Pagamento de equipe no dia 15.\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Verificar entregas do período | Atendimento | Líder de BU | — | Financeiro |\n| Emitir NF (nota fiscal) | Financeiro | Ruy Lima (> R$30k) | Contabilidade | Atendimento |\n| Enviar cobrança ao cliente | Financeiro | — | Atendimento | Ruy Lima |\n| Conciliar pagamentos | Financeiro | — | — | Marco, Ruy |\n| Lançar no DRE | Financeiro | Marco Andolfato | Contabilidade | — |\n| Acionar SOP de inadimplência | Financeiro | Ruy Lima | — | Marco |\n\n### 4. Pré-requisitos\n\n- [ ] Contrato assinado com cliente (valor, prazo de pagamento, forma — Pix/Boleto/TED)\n- [ ] Marcos de entrega do projeto definidos no TBO OS\n- [ ] Dados fiscais do cliente atualizados (CNPJ, endereço, e-mail fiscal)\n- [ ] Acesso ao sistema de emissão de NF (Nota fiscal municipal/estadual conforme serviço)\n- [ ] Conta bancária TBO com acesso para conciliação\n- [ ] Planilha de controle de recebíveis ou módulo financeiro do TBO OS\n\n### 5. Procedimento\n\n**5.1 Ciclo Mensal de Faturamento (abertura: todo dia 13-14)**\n\n1. Financeiro acessa TBO OS → módulo de Entregas e Projetos\n2. Listar todas as entregas confirmadas no período (dia 15 ao dia 14 atual):\n   - Contratos de retainer: faturar valor fixo mensal\n   - Projetos por marco: faturar apenas marcos concluídos e aprovados pelo cliente\n   - Extras/adicionais: verificar aprovações formais (e-mail, Asana ou TBO OS)\n3. Validar com Atendimento: "Entrega X foi aprovada pelo cliente? Posso faturar?"\n4. Montar lista de faturamento do mês com: cliente, valor, tipo de serviço, data de emissão\n\n**5.2 Emissão de Nota Fiscal**\n\n1. Emitir NF para cada cliente no sistema municipal/estadual:\n   - **Verificar dados obrigatórios:** razão social exata do CNPJ, endereço, município, código de serviço (LC 116/2003)\n   - **Alíquota ISS:** verificar com contabilidade para cada tipo de serviço e município do cliente\n   - **Descrição do serviço:** clara e compatível com o contrato (evitar "serviços de consultoria" genérico)\n2. Regra: NF emitida = faturamento confirmado. Nunca emitir antes da entrega aprovada.\n3. Download do XML + PDF da NF e arquivar em: `FINANCEIRO/NF/[ANO]/[MES]/`\n4. Para NF > R$30k: aprovação de Ruy antes de emitir\n\n**5.3 Envio de Cobrança ao Cliente**\n\n1. Enviar e-mail de cobrança com:\n   - NF em PDF em anexo\n   - Resumo do que está sendo cobrado (entregas do período)\n   - Valor, forma de pagamento (Pix TBO, dados bancários, boleto se aplicável)\n   - Data de vencimento (conforme contrato)\n   - Contato para dúvidas (financeiro@agenciatbo.com.br)\n2. Registrar no TBO OS: data de emissão, valor, vencimento, status = "aguardando"\n3. Para clientes com histórico de atraso: ligação de cortesia 3 dias antes do vencimento\n\n**5.4 Acompanhamento de Recebimentos**\n\nCalendário de acompanhamento:\n- **D-3 (3 dias antes do vencimento):** verificar se o cliente confirmou pagamento. Se sem confirmação: e-mail de lembrete gentil.\n- **D+0 (dia do vencimento):** verificar extrato bancário. Se não recebido: registrar como "em atraso".\n- **D+1 a D+5:** acionar SOP de cobrança inicial (e-mail + WhatsApp). Manter tom profissional.\n- **D+6 a D+30:** acionar SOP tbo-fin-005 (Gestão de Inadimplência).\n\n**5.5 Conciliação de Recebimentos**\n\n1. Todo dia útil: verificar extrato bancário\n2. Para cada entrada: identificar cliente, NF correspondente, valor\n3. Atualizar TBO OS: status da NF → "recebido" + data de recebimento\n4. Divergências (valor diferente, cliente não identificado): investigar antes de fechar\n5. Ao final do ciclo (dia 15): exportar relatório de recebíveis do mês para DRE\n\n**5.6 Fechamento do Ciclo (todo dia 15)**\n\n1. Totalizar: NFs emitidas no período | NFs recebidas | NFs em aberto (atraso)\n2. Calcular: taxa de recebimento no prazo (meta: > 90%)\n3. Transferir dados para DRE mensal (SOP tbo-fin-003)\n4. Projeção dos próximos 45 dias: listar NFs a emitir (retainers + marcos previstos)\n5. Compartilhar relatório com Marco e Ruy (até dia 17 de cada mês)\n\n### 6. Checklist de Validação\n\n**Faturamento:**\n- [ ] Todas as entregas aprovadas do período identificadas\n- [ ] NF emitida para 100% das entregas aprovadas\n- [ ] NFs > R$30k aprovadas por Ruy antes de emitir\n- [ ] XML + PDF arquivados na pasta correta\n- [ ] Dados fiscais do cliente verificados (CNPJ correto, endereço, alíquota ISS)\n\n**Cobrança:**\n- [ ] E-mail de cobrança enviado com NF em anexo\n- [ ] Data de vencimento registrada no TBO OS\n- [ ] Status no TBO OS atualizado para "aguardando"\n\n**Recebimentos:**\n- [ ] Extrato bancário verificado todo dia útil\n- [ ] Toda entrada conciliada com NF correspondente\n- [ ] Status das NFs atualizado (recebido/em atraso)\n\n**Fechamento:**\n- [ ] DRE atualizado com recebimentos do ciclo\n- [ ] Relatório enviado a Marco e Ruy até dia 17\n- [ ] Projeção de 45 dias atualizada\n\n### 7. Ferramentas e Recursos\n\n- **TBO OS — Módulo Financeiro**: controle de NFs, recebíveis, status de pagamento\n- **Prefeitura Municipal / SEFAZ**: emissão de NF de serviços (NFSe) ou produtos\n- **Conta bancária TBO**: extrato para conciliação (acesso via internet banking ou Open Finance)\n- **Planilha DRE TBO**: template mensal (exportação do TBO OS)\n- **Contabilidade parceira**: dúvidas sobre código de serviço, alíquotas ISS, retenções\n- **Gmail**: e-mails de cobrança (cc financeiro@agenciatbo.com.br)\n\n### 8. SLAs e Métricas\n\n| Métrica | Meta |\n|---|---|\n| NF emitida após entrega aprovada | < 48 horas |\n| E-mail de cobrança após emissão de NF | Mesmo dia da emissão |\n| Taxa de recebimento no prazo | > 90% |\n| Conciliação diária do extrato | Todo dia útil, até 11h |\n| Relatório financeiro para diretoria | Até dia 17 de cada mês |\n| Zero NF emitida sem entrega aprovada | 100% — zero exceções |\n\n**KPIs de saúde financeira:**\n- Receita recebida vs. faturada no mês: > 90%\n- Dias médios de recebimento (DSO): < 25 dias\n- NFs em aberto > 30 dias: < 5% do faturamento total\n\n### 9. Troubleshooting\n\n**Cliente solicita nota com CNPJ diferente do contrato:**\n→ Nunca emitir sem validação jurídica. Consultar Ruy e contabilidade.\n→ Se for grupo econômico legítimo: solicitar contrato aditivo antes de emitir.\n→ Documento necessário: razão social, CNPJ, endereço, e responsável pela aprovação.\n\n**Cliente questiona valor da NF:**\n→ Não cancelar NF imediatamente. Investigar primeiro.\n→ Se erro da TBO: cancelar e reemitir com prazo de vencimento recalculado.\n→ Se entendimento divergente: enviar memória de cálculo e aguardar validação.\n\n**Pagamento recebido mas NF não identificada:**\n→ Verificar extrato com atenção (pode ser valor parcial, dois pagamentos juntos, etc.)\n→ Se não identificado em 24h: contatar cliente para confirmação de qual NF está pagando.\n→ Nunca baixar NF como "recebida" sem confirmação.\n\n**Cliente solicita prazo maior para pagar:**\n→ Ruy Lima aprova renegociação de prazo.\n→ Registrar novo vencimento no TBO OS com nota da aprovação.\n→ Se atraso > 30 dias sem acordo: acionar SOP tbo-fin-005 (Inadimplência).\n\n**Erro na NF (dado errado, valor errado):**\n→ Cancelar NF imediatamente (prazo máximo de cancelamento varia por município — geralmente até 24h ou até o pagamento).\n→ Corrigir dados e reemitir.\n→ Notificar cliente sobre nova NF + novo vencimento (mesma data original).\n\n### 10. Template Anexo\n\n**Template: E-mail de Cobrança**\n```\nAssunto: [TBO] Fatura [MÊS/ANO] — [Nome do Cliente]\n\nOlá, [Nome],\n\nSegue em anexo a Nota Fiscal referente aos serviços prestados em [período]:\n\n📄 NF nº [número] — R$ [valor]\nServiços: [descrição resumida]\nVencimento: [data]\nPagamento: Pix — [chave Pix TBO]\n\nDados bancários (TED/DOC):\nBanco: [banco]\nAgência: [agência]\nConta: [conta]\nCNPJ: [CNPJ TBO]\n\nQualquer dúvida, estou à disposição.\n\n[Nome]\nFinanceiro TBO\nfinanceiro@agenciatbo.com.br\n```\n\n**Template: Relatório de Recebíveis (para envio a Marco e Ruy)**\n```markdown\n# Relatório Financeiro — [MÊS/ANO]\nEmitido em: [data] | Ciclo: [dia 15] a [dia 14 seguinte]\n\n## Faturamento do Período\n| Cliente | NF | Valor | Emissão | Vencimento | Status |\n|---|---|---|---|---|---|\n| | | | | | |\n\n**Total faturado:** R$ ___\n**Total recebido:** R$ ___\n**Total em aberto:** R$ ___\n**Taxa de recebimento no prazo:** ____%\n\n## Em Atraso (> vencimento)\n| Cliente | Valor | Dias em atraso | Ação em andamento |\n|---|---|---|---|\n| | | | |\n\n## Projeção — Próximos 45 dias\n| Cliente | Estimativa | Vencimento previsto |\n|---|---|---|\n| | | |\n\n**Total projetado:** R$ ___\n```',
    '',
    'published',
    'critical',
    ARRAY['faturamento', 'contas a receber', 'nota fiscal', 'NF', 'cobrança', 'recebíveis', 'financeiro', 'DRE', 'conciliação'],
    1,
    2
  ) ON CONFLICT (tenant_id, slug) DO UPDATE SET
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    content = EXCLUDED.content,
    content_html = EXCLUDED.content_html,
    priority = EXCLUDED.priority,
    tags = EXCLUDED.tags,
    version = EXCLUDED.version,
    updated_at = NOW();

  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-fin-001-contas-a-receber-e-faturamento';

  DELETE FROM knowledge_sop_steps WHERE sop_id = v_sop_id;

  INSERT INTO knowledge_sop_steps (sop_id, title, content, content_html, order_index, step_type) VALUES
  (v_sop_id, 'Objetivo', E'Garantir que 100% das entregas realizadas sejam faturadas corretamente, cobradas no prazo e recebidas de acordo com o contrato. Zero receita não faturada. Zero NF emitida com dados errados. Fluxo de caixa previsível com visibilidade de 45 dias à frente.', '', 0, 'step'),
  (v_sop_id, 'Escopo', E'**Quem executa:** Financeiro TBO + Atendimento (confirmação de entrega) + Ruy Lima (aprovação em casos especiais)\n**Quando se aplica:** Todo faturamento mensal — retainers, marcos de projeto, adiantamentos, extras\n**Ciclo financeiro TBO:** Dia 15 ao dia 15 do mês seguinte. Pagamento de equipe no dia 15.\n**Limites:** Não cobre Contas a Pagar (SOP fin-002) nem DRE (SOP fin-003). Inadimplência avançada → SOP fin-005.', '', 1, 'step'),
  (v_sop_id, 'RACI — Responsabilidades', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Verificar entregas do período | Atendimento | Líder de BU | — | Financeiro |\n| Emitir NF | Financeiro | Ruy Lima (> R$30k) | Contabilidade | Atendimento |\n| Enviar cobrança ao cliente | Financeiro | — | Atendimento | Ruy Lima |\n| Conciliar pagamentos | Financeiro | — | — | Marco, Ruy |\n| Lançar no DRE | Financeiro | Marco Andolfato | Contabilidade | — |\n| Acionar SOP de inadimplência | Financeiro | Ruy Lima | — | Marco |', '', 2, 'step'),
  (v_sop_id, 'Pré-requisitos', E'- Contrato assinado com cliente (valor, prazo de pagamento, forma de pagamento)\n- Marcos de entrega do projeto definidos no TBO OS\n- Dados fiscais do cliente atualizados (CNPJ, endereço, e-mail fiscal)\n- Acesso ao sistema de emissão de NF\n- Conta bancária TBO com acesso para conciliação\n- Módulo financeiro do TBO OS configurado', '', 3, 'step'),
  (v_sop_id, 'Procedimento', E'**5.1 Abertura do ciclo (dias 13-14):** Listar entregas aprovadas do período no TBO OS. Separar retainers (valor fixo) de marcos (só se aprovados). Validar com Atendimento.\n\n**5.2 Emissão de NF:** Verificar dados fiscais do cliente. Emitir apenas após entrega aprovada. NF > R$30k: aprovação de Ruy. Arquivar XML + PDF.\n\n**5.3 Envio de cobrança:** E-mail com NF em anexo, valor, vencimento, Pix/dados bancários. Registrar no TBO OS (status: aguardando).\n\n**5.4 Acompanhamento:** D-3: verificar confirmação. D+0: checar extrato. D+1-D+5: cobrança gentil. D+6-D+30: SOP fin-005.\n\n**5.5 Conciliação diária:** Todo dia útil verificar extrato. Conciliar cada entrada com NF. Atualizar status no TBO OS.\n\n**5.6 Fechamento (dia 15):** Totalizar emitido/recebido/em aberto. Exportar para DRE. Projetar 45 dias à frente. Relatório para Marco e Ruy até dia 17.', '', 4, 'step'),
  (v_sop_id, 'Checklist de Validação', E'**Faturamento:**\n- [ ] 100% das entregas aprovadas identificadas\n- [ ] NF emitida para cada entrega aprovada\n- [ ] NFs > R$30k aprovadas por Ruy\n- [ ] XML + PDF arquivados\n- [ ] Dados fiscais verificados\n\n**Cobrança:**\n- [ ] E-mail enviado com NF em anexo\n- [ ] Vencimento registrado no TBO OS\n- [ ] Status = "aguardando"\n\n**Recebimentos:**\n- [ ] Extrato verificado todo dia útil\n- [ ] Toda entrada conciliada\n- [ ] Status das NFs atualizado\n\n**Fechamento:**\n- [ ] DRE atualizado\n- [ ] Relatório enviado até dia 17\n- [ ] Projeção 45 dias atualizada', '', 5, 'checkpoint'),
  (v_sop_id, 'Ferramentas e Recursos', E'- **TBO OS — Módulo Financeiro**: controle de NFs, recebíveis, status de pagamento\n- **Prefeitura / SEFAZ**: emissão de NFSe (serviços)\n- **Internet banking TBO**: extrato para conciliação\n- **Gmail**: e-mails de cobrança (financeiro@agenciatbo.com.br)\n- **Contabilidade parceira**: dúvidas sobre ISS, retenções, códigos de serviço', '', 6, 'tip'),
  (v_sop_id, 'SLAs e Métricas', E'| Métrica | Meta |\n|---|---|\n| NF emitida após entrega aprovada | < 48 horas |\n| E-mail de cobrança após emissão | Mesmo dia |\n| Taxa de recebimento no prazo | > 90% |\n| Conciliação diária | Todo dia útil, até 11h |\n| Relatório para diretoria | Até dia 17 de cada mês |\n\n**KPIs de saúde financeira:**\n- Receita recebida vs. faturada: > 90%\n- DSO (dias médios de recebimento): < 25 dias\n- NFs em aberto > 30 dias: < 5% do faturamento total', '', 7, 'note'),
  (v_sop_id, 'Troubleshooting', E'**CNPJ diferente do contrato:** Nunca emitir sem validação. Solicitar contrato aditivo.\n\n**Cliente questiona valor:** Não cancelar imediatamente. Investigar → se erro TBO: reemitir | se divergência: enviar memória de cálculo.\n\n**Pagamento não identificado:** Verificar extrato com atenção. Se não identificado em 24h: contatar cliente. Nunca baixar NF sem confirmação.\n\n**Cliente solicita prazo maior:** Ruy aprova renegociação. Registrar novo vencimento com nota de aprovação. Se > 30 dias sem acordo: SOP fin-005.\n\n**Erro na NF:** Cancelar imediatamente (dentro do prazo do município). Reemitir com dados corretos. Notificar cliente sobre nova NF.', '', 8, 'warning'),
  (v_sop_id, 'Templates Prontos para Uso', E'**E-mail de Cobrança e Relatório de Recebíveis** — templates completos disponíveis no conteúdo principal do SOP.\n\nO e-mail de cobrança inclui: número da NF, valor, vencimento, Pix e dados bancários TBO.\nO relatório de recebíveis inclui: tabela de NFs emitidas, status, total em aberto, projeção 45 dias.', '', 9, 'tip');

  RAISE NOTICE 'Batch 015 aplicado com sucesso. 3 SOPs melhorados: tbo-com-001, tbo-rh-001, tbo-fin-001.';
END $$;
